#include <iostream>

int main() {
    int n;
    std::cin >> n;

    int sum = 0;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        sum += val;
    }

    std::cout << "Sum: " << sum << "\n";
    return 0;
}

