solution_code:
#include <iostream>
#include <string>

int dispatch(const std::string& cmd, int n) {
    if (cmd == "double")  return 2 * n;
    if (cmd == "square")  return n * n;
    if (cmd == "negate")  return -n;
    return 0;
}

int main() {
    std::string cmd;
    int n;
    std::cin >> cmd >> n;
    std::cout << dispatch(cmd, n) << "\n";
    return 0;
}
